<?php

namespace Tests\Feature;

use Tests\TestCase;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Illuminate\Pagination\LengthAwarePaginator;
use Illuminate\Support\Collection;
use App\Models\User;
use App\Models\Product;
use DOMDocument;
use DOMXPath;

/**
 * Test HTML structure, semantic correctness, and quality of output generated by all Blade components.
 * This test class focuses specifically on task 2.3.3: Validate component HTML output.
 * 
 * Validates:
 * - HTML structure and nesting
 * - Semantic HTML elements
 * - Valid HTML attributes
 * - Proper ARIA attributes
 * - CSS class structure
 * - Element relationships and hierarchy
 * - HTML validation compliance
 * - Cross-browser compatibility markup
 */
class BladeComponentHtmlValidationTest extends TestCase
{
    use RefreshDatabase;

    protected function setUp(): void
    {
        parent::setUp();
        
        // Create test data for components that need it
        User::factory()->count(5)->create();
        Product::factory()->count(3)->create();
    }

    // ========================================
    // BUTTON COMPONENT HTML VALIDATION
    // ========================================

    /** @test */
    public function button_component_produces_valid_html_structure()
    {
        // Test button element
        $view = $this->blade('<x-ui.button variant="primary" size="lg">Click Me</x-ui.button>');
        $html = (string) $view;
        
        $this->assertValidHtml($html);
        $this->assertHtmlContainsElement($html, 'button');
        $this->assertHtmlElementHasAttribute($html, 'button', 'type', 'button');
        $this->assertHtmlElementHasClass($html, 'button', 'inline-flex');
        $this->assertHtmlElementHasClass($html, 'button', 'items-center');
        $this->assertHtmlElementHasClass($html, 'button', 'justify-center');
        
        // Test link element when href provided
        $view = $this->blade('<x-ui.button href="/test" variant="outline">Link Button</x-ui.button>');
        $html = (string) $view;
        
        $this->assertValidHtml($html);
        $this->assertHtmlContainsElement($html, 'a');
        $this->assertHtmlElementHasAttribute($html, 'a', 'href', '/test');
        $this->assertHtmlElementHasClass($html, 'a', 'inline-flex');
    }

    /** @test */
    public function button_component_has_proper_accessibility_attributes()
    {
        // Test disabled button accessibility
        $view = $this->blade('<x-ui.button disabled>Disabled Button</x-ui.button>');
        $html = (string) $view;
        
        $this->assertHtmlElementHasAttribute($html, 'button', 'disabled');
        $this->assertHtmlElementHasClass($html, 'button', 'disabled:pointer-events-none');
        $this->assertHtmlElementHasClass($html, 'button', 'disabled:opacity-50');
        
        // Test disabled link accessibility
        $view = $this->blade('<x-ui.button href="/test" disabled>Disabled Link</x-ui.button>');
        $html = (string) $view;
        
        $this->assertHtmlElementHasAttribute($html, 'a', 'aria-disabled', 'true');
        $this->assertHtmlElementHasAttribute($html, 'a', 'tabindex', '-1');
        
        // Test with custom aria attributes
        $view = $this->blade('<x-ui.button aria-label="Submit form" aria-describedby="help-text">Submit</x-ui.button>');
        $html = (string) $view;
        
        $this->assertHtmlElementHasAttribute($html, 'button', 'aria-label', 'Submit form');
        $this->assertHtmlElementHasAttribute($html, 'button', 'aria-describedby', 'help-text');
    }

    /** @test */
    public function button_component_handles_nested_content_properly()
    {
        $view = $this->blade('
            <x-ui.button variant="secondary">
                <svg class="w-4 h-4 mr-2" fill="currentColor" viewBox="0 0 20 20">
                    <path d="M10 12l-4-4h8l-4 4z"/>
