        $this->assertValidHtml($html);
        $this->assertHtmlContainsElement($html, 'svg');
        $this->assertHtmlElementHasAttribute($html, 'svg', 'viewBox', '0 0 20 20');
        $this->assertStringContainsString('Download', $html);
    }

