    /** @test */
    public function alert_component_generates_unique_ids()
    {
        $view1 = $this->blade('<x-ui.alert dismissible>Alert 1</x-ui.alert>');
        $view2 = $this->blade('<x-ui.alert dismissible>Alert 2</x-ui.alert>');
        
        $html1 = (string) $view1;
        $html2 = (string) $view2;
        
        $this->assertValidHtml($html1);
        $this->assertValidHtml($html2);
        
        // Extract IDs and ensure they're different
        preg_match('/id="(alert-[^"]+)"/', $html1, $matches1);
        preg_match('/id="(alert-[^"]+)"/', $html2, $matches2);
        
        $this->assertNotEmpty($matches1);
        $this->assertNotEmpty($matches2);
        $this->assertNotEquals($matches1[1], $matches2[1]);
    }

