    /** @test */
    public function loading_component_variants_produce_valid_html()
    {
        $variants = ['spinner', 'dots', 'bars'];
        
        foreach ($variants as $variant) {
            $view = $this->blade("<x-ui.loading variant=\"{$variant}\" />");
            $html = (string) $view;
            
            $this->assertValidHtml($html);
            $this->assertHtmlElementHasAttribute($html, 'div', 'role', 'status');
            $this->assertHtmlElementHasAttribute($html, 'div', 'aria-live', 'polite');
            
            // Each variant should have appropriate animation classes
            if ($variant === 'spinner') {
                $this->assertHtmlContainsElement($html, 'svg');
                $this->assertHtmlElementHasClass($html, 'svg', 'animate-spin');
            } elseif ($variant === 'dots') {
                $this->assertHtmlElementHasClass($html, 'div', 'animate-bounce');
            } elseif ($variant === 'bars') {
                $this->assertHtmlElementHasClass($html, 'div', 'animate-pulse');
            }
        }
    }

