    /** @test */
    public function components_handle_special_characters_safely()
    {
        $specialContent = '<script>alert("xss")</script>&lt;test&gt; "quotes" \'apostrophes\' &amp; symbols';
        
        $view = $this->blade("<x-ui.alert title=\"Special & Characters\">{$specialContent}</x-ui.alert>");
        $html = (string) $view;
        
        $this->assertValidHtml($html);
        
        // The content should be present but properly handled
        $this->assertStringContainsString('Special &amp; Characters', $html);
        $this->assertStringContainsString('&lt;test&gt;', $html);
        $this->assertStringContainsString('"quotes"', $html);
        $this->assertStringContainsString("'apostrophes'", $html);
        $this->assertStringContainsString('&amp; symbols', $html);
        
        // Note: Blade doesn't automatically escape content in slots by default
        // The script tag will be present but should be handled by the browser's XSS protection
        // In a real application, you would use {{ }} instead of {!! !!} for user content
    }

    // ========================================
    // HTML VALIDATION HELPER METHODS
    // ========================================

    /**
     * Assert that the given HTML is valid and well-formed
     */
    private function assertValidHtml(string $html): void
    {
        // Create a DOMDocument and load the HTML
        $dom = new DOMDocument();
        $dom->preserveWhiteSpace = false;
        $dom->formatOutput = true;
        
        // Suppress warnings for HTML5 elements and attributes
        libxml_use_internal_errors(true);
        
        // Wrap in a basic HTML structure for validation
        $wrappedHtml = '<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body>' . $html . '</body></html>';
        
        $result = $dom->loadHTML($wrappedHtml, LIBXML_HTML_NOIMPLIED | LIBXML_HTML_NODEFDTD);
        
        $errors = libxml_get_errors();
        libxml_clear_errors();
        
        // Filter out warnings about HTML5 elements/attributes and known issues
        $criticalErrors = array_filter($errors, function($error) {
            // Skip HTML5 element warnings
            $html5Elements = ['svg', 'path', 'circle', 'nav', 'main', 'section', 'article', 'aside', 'header', 'footer'];
            foreach ($html5Elements as $element) {
                if (strpos($error->message, "Tag {$element} invalid") !== false) {
                    return false;
                }
            }
            
            // Skip entity reference warnings for common HTML entities
            if (strpos($error->message, 'htmlParseEntityRef: expecting') !== false) {
                return false;
            }
            
            // Only report actual errors and fatal errors
            return $error->level === LIBXML_ERR_ERROR || $error->level === LIBXML_ERR_FATAL;
        });
        
        $this->assertTrue($result, 'HTML should be valid and parseable');
        $this->assertEmpty($criticalErrors, 'HTML should not have critical parsing errors: ' . print_r($criticalErrors, true));
    }

    /**
     * Assert that HTML contains a specific element
     */
    private function assertHtmlContainsElement(string $html, string $tagName): void
    {
        $this->assertStringContainsString("<{$tagName}", $html, "HTML should contain <{$tagName}> element");
    }

    /**
     * Assert that an HTML element has a specific attribute with a specific value
     */
    private function assertHtmlElementHasAttribute(string $html, string $tagName, string $attribute, string $value = null): void
    {
        if ($value === null) {
            // Just check for attribute existence
            $pattern = "/<{$tagName}[^>]*\\s{$attribute}(?:\\s|>|=)/i";
            $this->assertMatchesRegularExpression($pattern, $html, "Element <{$tagName}> should have attribute '{$attribute}'");
        } else {
            // Check for attribute with specific value - escape special regex characters
            $escapedValue = preg_quote($value, '/');
            $pattern = "/<{$tagName}[^>]*\\s{$attribute}=[\"']{$escapedValue}[\"']/i";
            $this->assertMatchesRegularExpression($pattern, $html, "Element <{$tagName}> should have attribute '{$attribute}' with value '{$value}'");
        }
    }

    /**
     * Assert that an HTML element has a specific CSS class
     */
    private function assertHtmlElementHasClass(string $html, string $tagName, string $className): void
    {
        // Match class attribute that contains the specific class
        $pattern = "/<{$tagName}[^>]*\\sclass=[\"'][^\"']*\\b{$className}\\b[^\"']*[\"']/i";
        $this->assertMatchesRegularExpression($pattern, $html, "Element <{$tagName}> should have CSS class '{$className}'");
    }

    /**
     * Assert that HTML structure follows semantic best practices
     */
    private function assertSemanticHtmlStructure(string $html): void
    {
        // Check for proper heading hierarchy
        if (strpos($html, '<h') !== false) {
            $this->assertMatchesRegularExpression('/<h[1-6][^>]*>/', $html, 'Headings should use proper h1-h6 tags');
        }
        
        // Check for proper list structure
        if (strpos($html, '<li') !== false) {
            $this->assertTrue(
                strpos($html, '<ul') !== false || strpos($html, '<ol') !== false,
                'List items should be contained within ul or ol elements'
            );
        }
        
        // Check for proper table structure
        if (strpos($html, '<td') !== false || strpos($html, '<th') !== false) {
            $this->assertStringContainsString('<table', $html, 'Table cells should be contained within table element');
            $this->assertTrue(
                strpos($html, '<thead') !== false || strpos($html, '<tbody') !== false,
                'Tables should have proper thead/tbody structure'
            );
        }
    }
